27053	int ds4_session_copy_logits(ds4_session *s, float *out, int cap) {
27054	    if (!s || !out || cap < (int)DS4_N_VOCAB) return 0;
27055	    memcpy(out, s->logits, (size_t)DS4_N_VOCAB * sizeof(out[0]));
27056	    return (int)DS4_N_VOCAB;
27057	}
27058	
27059	int ds4_session_set_logits(ds4_session *s, const float *logits, int n) {
27060	    if (!s || !logits || n != (int)DS4_N_VOCAB) return 1;
27061	    memcpy(s->logits, logits, (size_t)DS4_N_VOCAB * sizeof(s->logits[0]));
27062	    return 0;
27063	}
