27065	static int ds4_session_eval_internal(ds4_session *s, int token, bool probe_mtp,
27066	                                     char *err, size_t errlen) {
27067	    if (!s) return 1;
27068	    if (s->distributed) {
27069	        if (!s->checkpoint_valid) {
27070	            if (errlen) snprintf(err, errlen, "distributed decode requires a valid checkpoint");
27071	            return 1;
27072	        }
27073	        (void)probe_mtp;
27074	        return ds4_dist_session_eval(s->distributed,
27075	                                     s,
27076	                                     &s->checkpoint,
27077	                                     token,
27078	                                     s->logits,
27079	                                     err,
27080	                                     errlen);
27081	    }
27082	    if (ds4_session_is_cpu(s)) {
27083	        ds4_engine *e = s->engine;
27084	        forward_token_raw_swa_cpu_decode_scratch(s->logits,
27085	                                                 &e->model,
27086	                                                 &e->weights,
27087	                                                 &s->cpu_cache,
27088	                                                 token,
27089	                                                 (uint32_t)s->checkpoint.len,
27090	                                                 e->directional_steering_dirs,
27091	                                                 e->directional_steering_attn_scale,
27092	                                                 e->directional_steering_ffn_scale,
27093	                                                 &s->cpu_scratch);
27094	        token_vec_push(&s->checkpoint, token);
27095	        s->checkpoint_valid = true;
27096	        s->mtp_draft_valid = false;
27097	        (void)probe_mtp;
27098	        return 0;
27099	    }
27100	#ifdef DS4_NO_GPU
27101	    (void)s;
27102	    (void)token;
27103	    (void)probe_mtp;
27104	    snprintf(err, errlen, "GPU support is not compiled in");
27105	    return 1;
27106	#else
27107	    ds4_engine *e = s->engine;
27108	    const bool mtp_probe_log = getenv("DS4_MTP_PROBE") != NULL;
27109	    const bool mtp_should_draft =
27110	        probe_mtp && e->mtp_ready && s->mtp_logits &&
27111	        (e->mtp_draft_tokens > 1 || mtp_probe_log);
27112	    if (probe_mtp && s->mtp_draft_valid) {
27113	        if (mtp_probe_log) {
27114	            s->mtp_probe_total++;
27115	            if (s->mtp_draft_token == token) s->mtp_probe_hit++;
27116	            fprintf(stderr,
27117	                    "ds4: mtp probe token=%d draft=%d hit=%llu/%llu\n",
27118	                    token,
27119	                    s->mtp_draft_token,
27120	                    (unsigned long long)s->mtp_probe_hit,
27121	                    (unsigned long long)s->mtp_probe_total);
27122	        }
27123	        s->mtp_draft_valid = false;
27124	    }
27125	    if (!metal_graph_eval_token_raw_swa(&s->graph, &e->model, &e->weights,
27126	                                        (uint32_t)token,
27127	                                        (uint32_t)s->checkpoint.len,
27128	                                        s->logits))
27129	    {
27130	        snprintf(err, errlen, "%s decode failed", ds4_backend_name(e->backend));
27131	        s->checkpoint_valid = false;
27132	        return 1;
27133	    }
27134	    token_vec_push(&s->checkpoint, token);
27135	    if (mtp_should_draft) {
27136	        int mtp_top = -1;
27137	        if (metal_graph_eval_mtp_draft(&s->graph,
27138	                                       &e->model,
27139	                                       &e->weights,
27140	                                       &e->mtp_model,
27141	                                       &e->mtp_weights,
27142	                                       token,
27143	                                       (uint32_t)(s->checkpoint.len - 1),
27144	                                       getenv("DS4_MTP_FULL_LOGITS") ? s->mtp_logits : NULL,
27145	                                       &mtp_top)) {
27146	            s->mtp_draft_token = mtp_top >= 0 ? mtp_top : sample_argmax(s->mtp_logits, DS4_N_VOCAB);
27147	            s->mtp_draft_valid = true;
27148	        } else if (getenv("DS4_MTP_PROBE")) {
27149	            fprintf(stderr, "ds4: mtp probe draft failed\n");
27150	        }
27151	    }
27152	    return 0;
27153	#endif
27154	}
