27156	int ds4_session_eval(ds4_session *s, int token, char *err, size_t errlen) {
27157	    return ds4_session_eval_internal(s, token, true, err, errlen);
27158	}
27159	
27160	/* Speculative decode state machine:
27161	 * 1. commit the normal target token and use its logits to validate draft[0];
27162	 * 2. let MTP recursively draft a tiny suffix from its own raw-cache frontier;
27163	 * 3. verify the suffix with the target graph, committing only the accepted
27164	 *    prefix and rolling back speculative Metal state on miss;
27165	 * 4. fall back to ordinary one-token decode if the fast verifier cannot prove
27166	 *    the target stream. */
27167	int ds4_session_eval_speculative_argmax(ds4_session *s, int first_token,
27168	                                        int max_tokens, int eos_token,
27169	                                        int *accepted, int accepted_cap,
27170	                                        char *err, size_t errlen) {
27171	    if (!s || max_tokens <= 0 || accepted_cap <= 0) return 0;
27172	    if (s->distributed) {
27173	        if (!accepted) return 0;
27174	        if (ds4_session_eval(s, first_token, err, errlen) != 0) return -1;
27175	        accepted[0] = first_token;
27176	        return 1;
27177	    }
27178	    if (ds4_session_is_cpu(s)) {
27179	        (void)max_tokens;
27180	        (void)eos_token;
27181	        if (!accepted || accepted_cap <= 0) return 0;
27182	        if (ds4_session_eval(s, first_token, err, errlen) != 0) return -1;
27183	        accepted[0] = first_token;
27184	        return 1;
27185	    }
27186	#ifdef DS4_NO_GPU
27187	    (void)s; (void)first_token; (void)max_tokens; (void)eos_token;
27188	    (void)accepted; (void)accepted_cap;
27189	    snprintf(err, errlen, "GPU support is not compiled in");
27190	    return -1;
27191	#else
27192	    ds4_engine *e = s->engine;
27193	
27194	    /*
27195	     * MTP in DeepSeek V4 is a speculative drafter, not a replacement sampler.
27196	     * The target model still defines the exact output stream.  A cycle starts
27197	     * by accepting one normal target token, then asks the MTP block to propose
27198	     * a short suffix.  The suffix is useful only if the target model can verify
27199	     * several proposed positions together; running ordinary decode once per
27200	     * draft token is correctness-safe but cannot be faster than baseline.
27201	     */
27202	    if (ds4_session_eval(s, first_token, err, errlen) != 0) return -1;
27203	    int n_accept = 0;
27204	    accepted[n_accept++] = first_token;
27205	    if (first_token == eos_token || max_tokens == 1 || n_accept >= accepted_cap) return n_accept;
27206	
