    dsml_decode_state dsml_state = j->req.kind == REQ_CHAT && j->req.has_tools ?
        dsml_tracker.decode : DSML_DECODE_OUTSIDE;
    const bool in_tool_call = dsml_decode_state_is_tool(dsml_state);
